  ('medical-tech-moex-10825', 'medical-tech', 'medical-tech-moex-104-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '使用特異性寡核苷酸探針（Sequence-specific oligonucleotide probe）做HLA分型，第一個 探針結合HLA-DRB*09:01-09:05，第二個探針結合HLA-DRB*09:02/09:03，第三個探針結合 HLA-DRB*09:03-09:05。實驗結果發現只有第一個跟第二個探針有結合至待測DNA，則待測 DNA的HLA-DRB是屬於下列那一型？', '["HLA-DRB*09:01", "HLA-DRB*09:02", "HLA-DRB*09:03", "HLA-DRB*09:04"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:41+00:00", "source_pdf_sha1": "51c839d0cd7d", "answer_pdf_sha1": "9e674626cf68", "source_family": "moex-gov-tw", "moex": {"exam_code": "104090", "c": "308", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "104", "exam_name": "104年第二次專技醫師牙醫師藥師分階段考試藥師醫檢師醫放師助產師物理職能呼吸治療師獸醫師考試", "original_question_number": 73, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
